"""GENERATED click donor pair — inlined so a Click track can be added with NO external
control files. Regenerate via `donorpack.write_click_data(control_root)`. Sources:
'2 stereo tracks.ptx' (clean) + '2 stereo plus click.ptx' (with click); their structural
diff is the click footprint that `add_click_anyN` re-keys onto any target session."""
import base64 as _b64, zlib as _z

_CLEAN = ""
_CLICK = ""

def _dec(s): return _z.decompress(_b64.b64decode(s))
def click_pair(): return _dec(_CLEAN), _dec(_CLICK)   # (clean_ref, click_ref)
